```typescript
import {
  ImageModelV3,
  ProviderV3,
  SpeechModelV3,
  TranscriptionModelV3,
  Experimental_VideoModelV3,
} from '@ai-sdk/provider';
import {
  FetchFunction,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';

export interface YourProviderSettings {
  apiKey?: string;
  baseURL?: string;
  headers?: Record<string, string>;
  fetch?: FetchFunction;
}

export interface YourProvider extends ProviderV3 {
  image(modelId: YourImageModelId): ImageModelV3;
  imageModel(modelId: YourImageModelId): ImageModelV3;
  transcription(modelId: YourTranscriptionModelId): TranscriptionModelV3;
  speech(modelId: YourSpeechModelId): SpeechModelV3;
  video(modelId: YourVideoModelId): Experimental_VideoModelV3;
  videoModel(modelId: YourVideoModelId): Experimental_VideoModelV3;
}

const defaultBaseURL = 'https://api.your-provider.com';

function loadYourApiKey({
  apiKey,
  description = 'your-provider',
}: {
  apiKey: string | undefined;
  description?: string;
}): string {
  if (typeof apiKey === 'string') {
    return apiKey;
  }

  let envApiKey = process.env.YOUR_PROVIDER_API_KEY;
  if (envApiKey == null) {
    throw new Error(`${description} API key is missing...`);
  }

  return envApiKey;
}

export function createYour(options: YourProviderSettings = {}): YourProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? defaultBaseURL);
  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadYourApiKey({ apiKey: options.apiKey })}`,
        ...options.headers,
      },
      `ai-sdk/your/${VERSION}`,
    );

  const createImageModel = (modelId: YourImageModelId) =>
    new YourImageModel(modelId, {
      provider: 'your.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  return {
    specificationVersion: 'v3' as const,
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
      });
    },
    // ... other model methods
  };
}

export const your = createYour();
```

