        {
          "image_url": "https://example.com/input.png",
          "num_images": 1,
          "prompt": "Edit this image",
        }
      `);
    });

    it('should send edit request with base64 string data', async () => {
      await createBasicModel().doGenerate({
        prompt: 'Edit this image',
        files: [
          {
            type: 'file',
            data: 'iVBORw0KGgoAAAANSUhEUgAAAAE=',
