            fileSize: null,
            nsfw: false,
          },
        ],
        timings: { inference: 5.875932216644287 },
        seed: 328395684,
      });
    });

    it('should handle empty timings object', async () => {
      server.urls['https://api.example.com/fal-ai/qwen-image'].response = {
        type: 'json-value',
        body: {
          images: [
            {
              url: 'https://api.example.com/image.png',
              content_type: 'image/png',
              file_name: null,
              file_size: null,
              width: 880,
              height: 1184,
