import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import type { Resolvable } from '@ai-sdk/provider-utils';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  FetchFunction,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { pixelArtImageModelOptionsSchema } from './pixelart-image-options';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: Resolvable<Record<string, string | undefined>>;
  fetch?: FetchFunction;
  _internal?: {
    currentDate?: () => Date;
  };
}

// PixelArt API response schema for a single generated image.
const pixelArtImageSchema = z.object({
  /** Base64-encoded image data. */
  b64_json: z.string(),
  width: z.number().nullish(),
  height: z.number().nullish(),
  /** Image format, e.g. "png" or "gif". */
  format: z.string().nullish(),
});

// Top-level response envelope returned by POST /images/generate.
const pixelArtResponseSchema = z.object({
  images: z.array(pixelArtImageSchema),
  /** Echo of the model ID used for generation. */
  model: z.string().nullish(),
  /** Seed used for generation (useful for reproducibility). */
  seed: z.number().nullish(),
});

// Error envelope returned by the PixelArt API on failure.
const pixelArtErrorSchema = z.object({
  error: z.object({
    code: z.string().nullish(),
    message: z.string(),
  }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => error.error.message,
});

/**
 * Decodes a base64 string to a `Uint8Array`.
 * Uses the globally available `atob` function (Node ≥16, browsers, Edge runtime).
 */
function base64ToUint8Array(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const bytes = new Uint8Array(binaryString.length);
  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  /** PixelArt API supports up to 4 images per call. */
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const warnings: Array<SharedV3Warning> = [];

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions: options.providerOptions,
      schema: pixelArtImageModelOptionsSchema,
    });

    // Warn when the caller provides aspectRatio but no size — the PixelArt
    // API only accepts explicit width×height dimensions via the `size` field.
    if (options.aspectRatio != null && options.size == null) {
      warnings.push({
        type: 'unsupported-setting',
        setting: 'aspectRatio',
        details:
          'PixelArt AI does not support aspect ratio directly. ' +
          'Provide an explicit size (e.g. "512x512") instead.',
      });
    }

    const requestBody: Record<string, unknown> = {
      prompt: options.prompt,
      model: this.modelId,
      n: options.n,
    };

    if (options.size != null) {
      requestBody.size = options.size;
    }

    if (options.seed != null) {
      requestBody.seed = options.seed;
    }

    if (pixelArtOptions?.style != null) {
      requestBody.style = pixelArtOptions.style;
    }

    if (pixelArtOptions?.pixelDensity != null) {
      requestBody.pixel_density = pixelArtOptions.pixelDensity;
    }

    if (pixelArtOptions?.outputFormat != null) {
      requestBody.output_format = pixelArtOptions.outputFormat;
    }

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(
        await resolve(this.config.headers),
        options.headers,
      ),
      body: requestBody,
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtResponseSchema,
      ),
      abortSignal: options.abortSignal,
      fetch: this.config.fetch,
    });

    // Decode each base64-encoded image into a raw Uint8Array.
    const images = value.images.map(image =>
      base64ToUint8Array(image.b64_json),
    );

    return {
      images,
      warnings,
      response: {
        modelId: this.modelId,
        timestamp: currentDate,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: value.images.map(image => ({
            width: image.width,
            height: image.height,
            format: image.format,
          })),
          ...(value.seed != null ? { seed: value.seed } : {}),
          ...(value.model != null ? { model: value.model } : {}),
        },
      },
    };
  }
}

