import { NoSuchModelError } from '@ai-sdk/provider';
import { describe, expect, it } from 'vitest';
import { createPixelArt, pixelArt } from './pixelart-provider';
import { PixelArtImageModel } from './pixelart-image-model';

describe('createPixelArt', () => {
  it('should create a provider instance with specificationVersion v3', () => {
    const provider = createPixelArt({ apiKey: 'test-key' });
    expect(provider.specificationVersion).toBe('v3');
  });

  describe('image / imageModel', () => {
    it('should create a PixelArtImageModel via image()', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-standard');
      expect(model).toBeInstanceOf(PixelArtImageModel);
      expect(model.modelId).toBe('pixelart-standard');
    });

    it('should create a PixelArtImageModel via imageModel()', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.imageModel('pixelart-hd');
      expect(model).toBeInstanceOf(PixelArtImageModel);
      expect(model.modelId).toBe('pixelart-hd');
    });

    it('should accept arbitrary model ID strings', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      const model = provider.image('pixelart-custom-v2');
      expect(model.modelId).toBe('pixelart-custom-v2');
    });

    it('should respect a custom baseURL', () => {
      const provider = createPixelArt({
        apiKey: 'test-key',
        baseURL: 'https://custom.example.com/api',
      });
      const model = provider.image('pixelart-standard') as PixelArtImageModel;
      // The model is correctly instantiated; URL is verified in integration tests.
      expect(model).toBeInstanceOf(PixelArtImageModel);
    });
  });

  describe('unsupported model types', () => {
    it('should throw NoSuchModelError for languageModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.languageModel('gpt-4')).toThrow(NoSuchModelError);
    });

    it('should throw NoSuchModelError for embeddingModel', () => {
      const provider = createPixelArt({ apiKey: 'test-key' });
      expect(() => provider.embeddingModel('text-embedding-3')).toThrow(
        NoSuchModelError,
      );
    });
  });
});

describe('pixelArt singleton', () => {
  it('should be a pre-created provider instance', () => {
    expect(pixelArt.specificationVersion).toBe('v3');
  });

  it('should create image models', () => {
    const model = pixelArt.image('pixelart-standard');
    expect(model).toBeInstanceOf(PixelArtImageModel);
  });
});

